using BenchmarkDotNet.Attributes;
using BenchmarkDotNet.Running;
using BenchmarkDotNet.Jobs;
using TextAnalysis;

[SimpleJob(RuntimeMoniker.Net90)]
[SimpleJob(RuntimeMoniker.Net100)]
[MemoryDiagnoser]
public class TextAnalyzerBenchmarks
{
    private TextAnalyzer _analyzer = null!;

    private const string SampleText =
        "The quick brown fox jumps over the lazy dog. " +
        "A benchmark measures performance of code across different runtime versions. " +
        "This text contains enough words to exercise the analyzer methods meaningfully. " +
        "Repeated words like the and of and in help test unique word counting logic. " +
        "Longer words like performance and meaningfully contribute to histogram variance.";

    [GlobalSetup]
    public void Setup()
    {
        _analyzer = new TextAnalyzer(SampleText);
    }

    [Benchmark]
    public double AverageWordLength() => _analyzer.AverageWordLength();

    [Benchmark]
    public object WordLengthHistogram() => _analyzer.WordLengthHistogram();

    [Benchmark]
    public int UniqueWordCount() => _analyzer.UniqueWordCount();
}

public class Program
{
    public static void Main(string[] args)
    {
        BenchmarkRunner.Run<TextAnalyzerBenchmarks>(args: args);
    }
}

